import { PermissionDocumentInput } from '../models';
import { invoiceCashbackPermissionRepository } from '../repository';

class InvoiceCashbackPermissionService {
  private readonly repository = invoiceCashbackPermissionRepository;

  async hasRedeemed(accountId: string): Promise<boolean> {
    const result = await this.repository.getPermission({ accountNumber: accountId });
    const redeemedAt = result?.invoiceCashbackRedemption?.redeemedAtDate;
    return Boolean(redeemedAt);
  }

  async markAsRedeemed(accountId: string): Promise<void> {
    const document: PermissionDocumentInput = {
      codigoCliente: accountId,
      status: 1,
      value: JSON.stringify({
        invoiceCashbackRedemption: {
          redeemedAtDate: new Date().toISOString(),
        },
      }),
    };
    await this.repository.savePermission(document);
  }
}

export const invoiceCashbackPermissionService = new InvoiceCashbackPermissionService();

